/**
 * Helper class for MinHeap implementation required for Dijkstra's algorithm.
 * Stores [distance, node] pairs.
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    getParentIndex(i) {
        return Math.floor((i - 1) / 2);
    }

    getLeftChildIndex(i) {
        return 2 * i + 1;
    }

    getRightChildIndex(i) {
        return 2 * i + 2;
    }

    swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    // Compares based on distance (the first element of the stored array)
    bubbleUp(index) {
        while (index > 0) {
            const parentIndex = this.getParentIndex(index);
            if (this.heap[index][0] < this.heap[parentIndex][0]) {
                this.swap(index, parentIndex);
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    bubbleDown(index) {
        const lastIndex = this.heap.length - 1;
        while (true) {
            let left = this.getLeftChildIndex(index);
            let right = this.getRightChildIndex(index);
            let smallest = index;

            // Check left child
            if (left <= lastIndex && this.heap[left][0] < this.heap[smallest][0]) {
                smallest = left;
            }

            // Check right child
            if (right <= lastIndex && this.heap[right][0] < this.heap[smallest][0]) {
                smallest = right;
            }

            if (smallest !== index) {
                this.swap(index, smallest);
                index = smallest;
            } else {
                break;
            }
        }
    }

    insert(element) {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    extractMin() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown(0);
        return min;
    }
}


/**
 * Runs Dijkstra's algorithm from a single source node.
 * @param {number} n - Number of nodes.
 * @param {Array<Array<[number, number]>>} adj - Adjacency list: adj[u] = [[v, weight], ...].
 * @param {number} startNode - The source node.
 * @returns {Array<number>} Array of shortest distances from startNode to all other nodes.
 */
function dijkstra(n, adj, startNode) {
    const distances = new Array(n).fill(Infinity);
    distances[startNode] = 0;

    // PQ stores [distance, node]
    const pq = new MinPriorityQueue();
    pq.insert([0, startNode]);

    while (!pq.isEmpty()) {
        const [d, u] = pq.extractMin();

        if (d > distances[u]) {
            continue;
        }

        for (const edge of adj[u]) {
            const v = edge[0];
            const weight = edge[1];

            const newDist = distances[u] + weight;

            if (newDist < distances[v]) {
                distances[v] = newDist;
                pq.insert([newDist, v]);
            }
        }
    }
    return distances;
}


function solve(n, prices, roads) {
    // Step 1: Build Adjacency Lists

    // adj_empty: weights = cost_i (Empty Hand Travel i -> j)
    const adj_empty = Array.from({ length: n }, () => []);

    // adj_full: weights = cost_i * tax_i (Full Hand Travel j -> i)
    const adj_full = Array.from({ length: n }, () => []);

    for (const road of roads) {
        const [u, v, cost, tax] = road;

        // Bidirectional edges

        // Empty Hand costs
        adj_empty[u].push([v, cost]);
        adj_empty[v].push([u, cost]);

        // Full Hand costs
        const fullCost = cost * tax;
        adj_full[u].push([v, fullCost]);
        adj_full[v].push([u, fullCost]);
    }

    // Step 2: Calculate All-Pairs Shortest Paths (APSP)

    // D_empty[i][j] = Shortest path cost from i to j (Empty Hand)
    const D_empty = Array.from({ length: n }, () => new Array(n).fill(Infinity));
    for (let i = 0; i < n; i++) {
        const dists = dijkstra(n, adj_empty, i);
        for (let j = 0; j < n; j++) {
            D_empty[i][j] = dists[j];
        }
    }

    // D_full[i][j] = Shortest path cost from i to j (Full Hand)
    // Note: We use D_full[i][j] for path j -> i in the formula C_i->j = D_empty(i, j) + prices[j] + D_full(j, i)
    // Since the full hand graph is undirected, D_full[j][i] = D_full[i][j].
    const D_full = Array.from({ length: n }, () => new Array(n).fill(Infinity));
    for (let i = 0; i < n; i++) {
        const dists = dijkstra(n, adj_full, i);
        for (let j = 0; j < n; j++) {
            D_full[i][j] = dists[j];
        }
    }


    // Step 3: Calculate the minimum cost for each store i
    const ans = new Array(n);

    for (let i = 0; i < n; i++) {
        // Option 1: Direct purchase
        let minCost = prices[i];

        // Option 2: Travel to j, buy at j, return to i
        for (let j = 0; j < n; j++) {
            if (i === j) continue;

            // C_i->j = D_empty(i, j) + prices[j] + D_full(j, i)

            const emptyTravelCost = D_empty[i][j];
            const fullTravelCost = D_full[j][i]; // D_full[i][j] since undirected

            // Check if paths exist
            if (emptyTravelCost !== Infinity && fullTravelCost !== Infinity) {
                // Note: Prices and costs can be large, standard JS numbers should handle up to 2^53 - 1.
                // Max cost is ~10^14, which is safe.
                const totalCostViaJ = emptyTravelCost + prices[j] + fullTravelCost;
                if (totalCostViaJ < minCost) {
                    minCost = totalCostViaJ;
                }
            }
        }
        ans[i] = minCost;
    }

    return ans;
}

