/**
 * Helper class for MinHeap implementation required for Dijkstra's algorithm.
 * Stores [distance, node] pairs.
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    getParentIndex(i) {
        return Math.floor((i - 1) / 2);
    }

    getLeftChildIndex(i) {
        return 2 * i + 1;
    }

    getRightChildIndex(i) {
        return 2 * i + 2;
    }

    swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    // Compares based on distance (the first element of the stored array)
    bubbleUp(index) {
        while (index > 0) {
            const parentIndex = this.getParentIndex(index);
            if (this.heap[index][0] < this.heap[parentIndex][0]) {
                this.swap(index, parentIndex);
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    bubbleDown(index) {
        const lastIndex = this.heap.length - 1;
        while (true) {
            let left = this.getLeftChildIndex(index);
            let right = this.getRightChildIndex(index);
            let smallest = index;

            // Check left child
            if (left <= lastIndex && this.heap[left][0] < this.heap[smallest][0]) {
                smallest = left;
            }

            // Check right child
            if (right <= lastIndex && this.heap[right][0] < this.heap[smallest][0]) {
                smallest = right;
            }

            if (smallest !== index) {
                this.swap(index, smallest);
                index = smallest;
            } else {
                break;
            }
        }
    }

    insert(element) {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    extractMin() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown(0);
        return min;
    }
}


/**
 * Runs Dijkstra's algorithm from a single source node.
 * @param {number} n - Number of nodes.
 * @param {Array<Array<[number, number]>>} adj - Adjacency list: adj[u] = [[v, weight], ...].
 * @param {number} startNode - The source node.
 * @returns {Array<number>} Array of shortest distances from startNode to all other nodes.
 */
function dijkstra(n, adj, startNode) {
    const distances = new Array(n).fill(Infinity);
    distances[startNode] = 0;

    // PQ stores [distance, node]
    const pq = new MinPriorityQueue();
    pq.insert([0, startNode]);

    while (!pq.isEmpty()) {
        const [d, u] = pq.extractMin();

        if (d > distances[u]) {
            continue;
        }

        for (const edge of adj[u]) {
            const v = edge[0];
            const weight = edge[1];

            const newDist = distances[u] + weight;

            if (newDist < distances[v]) {
                distances[v] = newDist;
                pq.insert([newDist, v]);
            }
        }
    }
    return distances;
}


function solve(n, prices, roads) {
