    // adj_empty: weights = cost_i (Empty Hand Travel i -> j)
    const adj_empty = Array.from({ length: n }, () => []);

    // adj_full: weights = cost_i * tax_i (Full Hand Travel j -> i)
    const adj_full = Array.from({ length: n }, () => []);

    for (const road of roads) {
        const [u, v, cost, tax] = road;

        // Bidirectional edges

        // Empty Hand costs
        adj_empty[u].push([v, cost]);
        adj_empty[v].push([u, cost]);

        // Full Hand costs
        const fullCost = cost * tax;
        adj_full[u].push([v, fullCost]);
        adj_full[v].push([u, fullCost]);
    }

    // Step 2: Calculate All-Pairs Shortest Paths (APSP)

    // D_empty[i][j] = Shortest path cost from i to j (Empty Hand)
    const D_empty = Array.from({ length: n }, () => new Array(n).fill(Infinity));
    for (let i = 0; i < n; i++) {
        const dists = dijkstra(n, adj_empty, i);
        for (let j = 0; j < n; j++) {
            D_empty[i][j] = dists[j];
        }
    }

    // D_full[i][j] = Shortest path cost from i to j (Full Hand)
    // Note: We use D_full[i][j] for path j -> i in the formula C_i->j = D_empty(i, j) + prices[j] + D_full(j, i)
    // Since the full hand graph is undirected, D_full[j][i] = D_full[i][j].
    const D_full = Array.from({ length: n }, () => new Array(n).fill(Infinity));
    for (let i = 0; i < n; i++) {
        const dists = dijkstra(n, adj_full, i);
        for (let j = 0; j < n; j++) {
            D_full[i][j] = dists[j];
        }
    }


    // Step 3: Calculate the minimum cost for each store i
    const ans = new Array(n);

    for (let i = 0; i < n; i++) {
        // Option 1: Direct purchase
        let minCost = prices[i];

        // Option 2: Travel to j, buy at j, return to i
        for (let j = 0; j < n; j++) {
            if (i === j) continue;

            // C_i->j = D_empty(i, j) + prices[j] + D_full(j, i)

            const emptyTravelCost = D_empty[i][j];
            const fullTravelCost = D_full[j][i]; // D_full[i][j] since undirected

            // Check if paths exist
            if (emptyTravelCost !== Infinity && fullTravelCost !== Infinity) {
                // Note: Prices and costs can be large, standard JS numbers should handle up to 2^53 - 1.
                // Max cost is ~10^14, which is safe.
                const totalCostViaJ = emptyTravelCost + prices[j] + fullTravelCost;
                if (totalCostViaJ < minCost) {
                    minCost = totalCostViaJ;
                }
            }
        }
        ans[i] = minCost;
    }

    return ans;
}

